final:
module RefModule(
  output reg [2:0] cycle,
  input clk,
  input enn
);reg [2:0] obf_register = 3'b000;

  always @(posedge clk) begin
    if(!enn)
      obf_register <= (obf_register == 3'b111) ? 3'b000 : obf_register + 1;
    else
      obf_register <= 3'b000;
  end

  assign cycle = obf_register;

endmodule
